        rdfs:subClassOf  sosa:Procedure .

:AbstractEmissionPoint
        rdf:type         owl:Class ;
        rdfs:comment     "An abstract emission point is a conceptual emission point that does not necessarily have a fixed location, but does fulfill a functional role in the process."@en ;
